module top_module(
    input clk,
    input reset,
    output reg [3:0] bit_0,
    output reg [3:0] bit_1,
    output reg [3:0] bit_2,
    output reg [3:0] bit_3
);reg [3:0] invalid_counter;

always @(posedge clk) begin
    if (reset) begin
        invalid_counter <= 4'b0000;
    end else begin
        invalid_counter <= {invalid_counter[2:0], invalid_counter[3]};
    end
end

assign bit_0 = invalid_counter[0];
assign bit_1 = invalid_counter[1];
assign bit_2 = invalid_counter[2];
assign bit_3 = invalid_counter[3];

endmodule
